body .ui-picklist, body .ui-picklist.ui-picklist-responsive, body .ui-orderlist, body .ui-orderlist.ui-grid-responsive {

    .ui-picklist-buttons-cell, .ui-orderlist-controls {
        span.ui-button-icon-left.ui-icon, span.ui-button-icon-right.ui-icon {
            top:50%;
        }

        .ui-orderlist-button-move-up, .ui-orderlist-button-move-top {
            span.ui-button-icon-left.ui-icon, span.ui-button-icon-right.ui-icon {
                top:0;
            }
        }
    }

}

span.ui-icon.icon-ripple, div.ui-icon.icon-ripple {
    opacity: .9!important;

    &:before {
        border-radius: 50%;
        background-color: rgba(0,0,0,.12);
        background-size: 24px 24px;
        padding: 4px!important;
        height: 24px;
        width: 24px;
    }

    &.ui-icon-plusthick:before {
        padding-left: 5px!important;
    }
}

span.ui-icon-carat-1-e {
    background-image: none;
    display: inline;

    &:before {
        font-family: 'Glyphicons Halflings';
        color: #444444;
        position: relative;
        font-size: 10px;
        font-weight: bold;
        padding: 0 4px;
        top: 2px;
        overflow: hidden;
        content: "\e258" !important;
    }
}

&-body {
  display: flex;
  align-items: center;
  width: 100%;
  padding: 19px @h-spacing-large;
  padding: 19px var(--am-card-padding, @h-spacing-large);
  border-radius: @corner-radius-lg;
  border-radius: var(--am-card-border-radius, @corner-radius-lg);
  min-height: 85px;
  box-sizing: border-box;
  background-color: #929292;
  background-repeat: no-repeat;
  z-index: 2;
  position: relative;
  background-size: 100%;
}

&-buttons {
  position: relative;
  display: flex;
  font-size: @font-size-title;
  font-size: var(--am-modal-footer-fontSize, @font-size-title);
  color: @color-text-primary;
  color: var(--am-color-text-primary, @color-text-primary);
  text-align: center;
  .hairline('top', @modal-footer-border-color);
  &--vertical {
    flex-direction: column;
  }
  &--horizontal {
    flex-direction: row;
  }
}

&-input {
  box-sizing: content-box;
  padding-bottom: @v-spacing-standard;
  padding-bottom: var(--am-amount-input-padding-bottom, @v-spacing-standard);
  display: flex;
  align-items: baseline;
  width: 100%;
  height: 100rpx;
  overflow: hidden;
  position: relative;
  font-size: @font-size-amount-core;
  line-height: @line-height-base;
  line-height: var(--am-amount-input-line-height, @line-height-paragraph);
  .hairline("bottom");
}

> tbody:last-child,
    > tfoot:last-child {
      > tr:last-child {
        border-bottom-left-radius: (@panel-border-radius - 1);
        border-bottom-right-radius: (@panel-border-radius - 1);

        td:first-child,
        th:first-child {
          border-bottom-left-radius: (@panel-border-radius - 1);
        }
        td:last-child,
        th:last-child {
          border-bottom-right-radius: (@panel-border-radius - 1);
        }
      }
    }

> thead:first-child,
    > tbody:first-child {
      > tr:first-child {
        border-top-left-radius: (@panel-border-radius - 1);
        border-top-right-radius: (@panel-border-radius - 1);

        td:first-child,
        th:first-child {
          border-top-left-radius: (@panel-border-radius - 1);
        }
        td:last-child,
        th:last-child {
          border-top-right-radius: (@panel-border-radius - 1);
        }
      }
    }

&-horizontal {
  flex-direction: row;
  > .@{class-prefix-space}-item {
    margin-right: var(--gap-horizontal);
    &:last-child {
      margin-right: 0;
    }
  }
  &.@{class-prefix-space}-wrap {
    flex-wrap: wrap;
    margin-bottom: calc(var(--gap-vertical) * -1);
    > .@{class-prefix-space}-item {
      padding-bottom: var(--gap-vertical);
    }
  }
}

@media @media-hover-none {
    & when (@listing-grid-item-actions-secondary__position = absolute) {
        .product-item-inner,
        .actions-secondary {
            opacity: 1;
            pointer-events: all;
        }
    }
    & when not (@_hover-none-visible-height = false) {
        .actions-primary {
            opacity: 0;
            pointer-events: none;
        }
        .listing-reveal-on-hover-visible-height(@_aspect-ratio, @_hover-none-visible-height);
    }
}

tbody tr { // tbody is created per product
            &:not(:last-child) {
                border-bottom: 0;
            }
            + tr { // bundle items
                td:first-child {
                    .padding-left(@4);
                }
                &:not(:last-child) {
                    td {
                        padding-top: @1;
                        padding-bottom: @1;
                    }
                }
            }
        }

& when not (@navigation__media-wrap = false) {
    @media @navigation__media-wrap {
        .header.content {
            flex-wrap: wrap;
            > .navigation-wrapper {
                order: 9999;
                width: 100%;
                margin-bottom: -@2;

                .navigation > ul {
                    .margin-left(-@2);
                }
            }
        }
    }
}

@media (max-width: 800px) {
  .table--files,
  .table--history,
  .table--downloads {
    border-bottom-color: @subtext0 !important;
  }

  .table--files tbody tr td:first-child,
  .table--files tbody tr th:first-child,
  .table--history tbody tr td:first-child,
  .table--history tbody tr th:first-child,
  .table--downloads tbody tr td:first-child,
  .table--downloads tbody tr th:first-child {
    border-top-color: @subtext0 !important;
  }
}

[data-test-id="one-bar-navigation-arrows"] {
  &[style*="to left"]:not([style*="to right"]) {
    background: linear-gradient(to left, @base, transparent 40px)
      !important;
  }
  &[style*="to right"]:not([style*="to left"]) {
    background: linear-gradient(to right, @base, transparent 40px)
      !important;
  }
  &[style*="to left"][style*="to right"] {
    background:
      linear-gradient(to left, @base, transparent 40px),
      linear-gradient(to right, @base, transparent 40px) !important;
  }
}

&.bottom > .arrow {
  left: 50%;
  margin-left: -@popover-arrow-outer-width;
  border-top-width: 0;
  border-bottom-color: @popover-arrow-outer-fallback-color; // IE8 fallback
  border-bottom-color: @popover-arrow-outer-color;
  top: -@popover-arrow-outer-width;
  &:after {
    content: " ";
    top: 1px;
    margin-left: -@popover-arrow-width;
    border-top-width: 0;
    border-bottom-color: @popover-arrow-color;
  }
}

&.top > .arrow {
  left: 50%;
  margin-left: -@popover-arrow-outer-width;
  border-bottom-width: 0;
  border-top-color: @popover-arrow-outer-fallback-color; // IE8 fallback
  border-top-color: @popover-arrow-outer-color;
  bottom: -@popover-arrow-outer-width;
  &:after {
    content: " ";
    bottom: 1px;
    margin-left: -@popover-arrow-width;
    border-bottom-width: 0;
    border-top-color: @popover-arrow-color;
  }
}

&.left > .arrow {
  top: 50%;
  right: -@popover-arrow-outer-width;
  margin-top: -@popover-arrow-outer-width;
  border-right-width: 0;
  border-left-color: @popover-arrow-outer-fallback-color; // IE8 fallback
  border-left-color: @popover-arrow-outer-color;
  &:after {
    content: " ";
    right: 1px;
    border-right-width: 0;
    border-left-color: @popover-arrow-color;
    bottom: -@popover-arrow-width;
  }
}

&.right > .arrow {
  top: 50%;
  left: -@popover-arrow-outer-width;
  margin-top: -@popover-arrow-outer-width;
  border-left-width: 0;
  border-right-color: @popover-arrow-outer-fallback-color; // IE8 fallback
  border-right-color: @popover-arrow-outer-color;
  &:after {
    content: " ";
    left: 1px;
    bottom: -@popover-arrow-width;
    border-left-width: 0;
    border-right-color: @popover-arrow-color;
  }
}

& when not (@variationButtonColors = false) {
    each(@variationButtonColors, {
        @color: @value;
        @h: @colors[@@color][hover];
        @lh: @colors[@@color][lightHover];

        input[type="file"].ui.file.input:focus + label.ui.@{color}.button@{notBasic}@{notTertiary},
        .ui.file.input input[type="file"]:focus + label.ui.@{color}.button@{notBasic}@{notTertiary} {
            background-color: @h;
            color: @white;
            &.inverted when (@variationButtonInverted) {
                background-color: @lh;
            }
        }
    });
}

@media only screen and (max-width: @largestMobileScreen) {
    .ui.stackable.buttons {
        flex-direction: column;
        & .button:first-child {
            border-bottom-left-radius: 0;
            border-top-right-radius: @borderRadius;
        }
        & .button:last-child {
            border-bottom-left-radius: @borderRadius;
            border-top-right-radius: 0;
        }
        & .button:only-child {
            border-radius: @borderRadius;
        }
    }
}

& when not (@variationTransitionColors = false) {
    each(@variationTransitionColors, {
        @color: @value;
        @c: @colors[@@color][color];
        @l: @colors[@@color][light];

        .@{color}.pulsating.transition {
            box-shadow: 0 0 0 0 fade(@c, @pulsatingOpacity);
        }
        & when (@variationTransitionInverted) {
            .@{color}.inverted.pulsating.transition {
                box-shadow: 0 0 0 0 fade(@l, @pulsatingInvertedOpacity);
            }
        }
    });
}

i.icon {
    display: inline-block;
    opacity: @opacity;
    margin: 0 @distanceFromText 0 0;
    width: @width;
    height: @height;
    font-family: @fontName;
    font-style: normal;
    font-weight: @normal;
    text-decoration: inherit;
    text-align: center;
    speak: none;
    -moz-osx-font-smoothing: grayscale;
    -webkit-font-smoothing: antialiased;
    backface-visibility: hidden;
}

&-title {
    display: inline-block;
    margin: 0;
    padding: 0 4px;
    border-radius: @btn-border-radius-small;
    cursor: pointer;
    vertical-align: top;
    color: @text-color;
    transition: all @transition-time @ease-in-out;
    &:hover {
        background-color: tint(@primary-color, 90%);
    }
    &-selected, &-selected:hover{
        background-color: tint(@primary-color, 80%);
    }
}

&:before{
    content: '';
    display: none;
    width: 14px;
    height: 14px;
    border-radius: 50%;
    background-color: transparent;
    position: absolute;
    left: 3px;
    top: 3px;
    z-index: 1;
    border: 1px solid @primary-color;
    border-color: transparent transparent transparent @primary-color;
    animation: switch-loading 1s linear;
    animation-iteration-count: infinite;
}

&-disabled {
    border-color: @border-color-base;
    background-color: @background-color-base;
    cursor: @cursor-disabled;
    color: #ccc;

    &:first-child,
    &:hover {
        border-color: @border-color-base;
        background-color: @background-color-base;
        color: #ccc;
    }
    &:first-child {
        border-left-color: @border-color-base;
    }
}

&-bar-con {
    position: absolute;
    overflow: hidden;
    &.vertical {
        left: @trigger-bar-offset;
        top: 50%;
        height: @trigger-bar-con-height;
        transform: translate(0, -50%);
    }
    &.horizontal {
        left: 50%;
        top: @trigger-bar-offset;
        width: @trigger-bar-con-height;
        transform: translate(-50%, 0);
    }
}

&.is-blurred {
  .sheet-toolbar-container[data-id="Preferences"] .toolbar-window-controls {
    .close {
      background-image: url("mailspring://mailspring-theme-matcha/assets/@{theme_assets_directory}/titlebutton-close-backdrop.png");
    }

    .minimize {
      background-image: url("mailspring://mailspring-theme-matcha/assets/@{theme_assets_directory}/titlebutton-minimize-backdrop.png");
    }

    .maximize {
      background-image: url("mailspring://mailspring-theme-matcha/assets/@{theme_assets_directory}/titlebutton-maximize-backdrop.png");
    }
  }
}

&.is-blurred {
  .layout-mode-popout .toolbar-window-controls {
    .close {
      background-image: url("mailspring://mailspring-theme-matcha/assets/@{theme_assets_directory}/titlebutton-close-backdrop.png");
    }

    .minimize {
      background-image: url("mailspring://mailspring-theme-matcha/assets/@{theme_assets_directory}/titlebutton-minimize-backdrop.png");
    }

    .maximize {
      background-image: url("mailspring://mailspring-theme-matcha/assets/@{theme_assets_directory}/titlebutton-maximize-backdrop.png");
    }
  }
}

&.is-blurred {
  .toolbar-window-controls {
    .close {
      background-image: url("mailspring://mailspring-theme-matcha/assets/@{theme_assets_directory}/titlebutton-close-backdrop-dark.png");
    }

    .minimize {
      background-image: url("mailspring://mailspring-theme-matcha/assets/@{theme_assets_directory}/titlebutton-minimize-backdrop-dark.png");
    }

    .maximize {
      background-image: url("mailspring://mailspring-theme-matcha/assets/@{theme_assets_directory}/titlebutton-maximize-backdrop-dark.png");
    }
  }
}

&::before {
    position: absolute;
    left: 0.8rem;
    padding-top: 3px;
    font-family: 'argon' !important;
    font-style: normal;
    font-weight: normal;
    font-variant: normal;
    text-transform: none;
    line-height: 1;
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
    content: "\e915";
    color: var(--primary);
    transition: all 0.3s;
}
